async (page) => {
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/live_screen.png', type: 'png' }).catch(() => {});

  // Check what __clickTile returns and if character is stuck/in combat
  const state = JSON.parse(await page.evaluate(() => JSON.stringify(window.__latestGameState)));

  // Try clicking tile (177, 187) and capture full result
  const r = JSON.parse(await page.evaluate(({x,y}) => JSON.stringify(window.__clickTile(x,y)), {x:177, y:187}));

  return JSON.stringify({
    pos: state.player_position,
    hp: state.player_stats.hp + '/' + state.player_stats.max_hp,
    target: state.current_target ? state.current_target.name : null,
    is_dead: state.ui_state.is_dead,
    clickResult: r
  });
}
